queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?collection_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCollections ?child ; p:hasLibraries ?parent . } GROUP BY ?child }
  ?child p:collection_name ?collection_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Libraries } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?collection_name WHERE {
  ?libraries_collections a :Libraries_Collections .
  ?collections a :Collections .
  ?libraries_collections p:hasCollections ?collections .
  ?libraries a :Libraries .
  ?libraries_collections p:hasLibraries ?libraries .
  ?libraries p:name ?name .
  ?collections p:collection_name ?collection_name .
} }
  collective: { SELECT ?collection_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCollections ?child ; p:hasLibraries ?parent . } GROUP BY ?child }
  ?child p:collection_name ?collection_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Libraries } }
  FILTER(?nf = ?total)
} }
}
